Describe "Format-ReportAsJson" {
    BeforeAll {
        $secrets = @(
            [PSCustomObject]@{
                name               = "SECRET_ALPHA"
                lastRotated        = "2026-01-01"
                rotationPolicyDays = 90
                requiredBy         = @("api-service")
